def realize(X, y, rng):
    X = np.asarray(X, dtype=np.float64)
    n, d = X.shape
    if n == 0 or d == 0:
        return X.astype(np.float32)

    def robust_z(x):
        x = np.nan_to_num(x, nan=0.0, posinf=0.0, neginf=0.0)
        med = np.median(x)
        q75, q25 = np.percentile(x, 75), np.percentile(x, 25)
        iqr = q75 - q25
        if iqr > 1e-9:
            s = iqr / 1.349
        else:
            sd = x.std()
            s = sd if sd > 1e-9 else 1.0
        z = (x - med) / s
        return np.clip(z, -8.0, 8.0)

    def qbin(z, k):
        qs = np.quantile(z, np.linspace(0.0, 1.0, k + 1)[1:-1])
        qs = np.unique(qs)
        if qs.size == 0:
            return np.zeros_like(z)
        return np.searchsorted(qs, z, side='right').astype(np.float64)

    out = np.empty((n, d), dtype=np.float64)

    # --- per-column monotone treatments, mixed by rng ---
    # weights: many discrete/low-cardinality cols, some skewed/heavy-tailed,
    # some bounded/censored, a few near-linear continuous
    kinds = rng.choice(
        np.array(['bin', 'count', 'binary', 'lognorm', 'power', 'censor', 'linear']),
        size=d,
        p=[0.26, 0.16, 0.08, 0.20, 0.12, 0.12, 0.06],
    )

    for j in range(d):
        z = robust_z(X[:, j])
        if np.ptp(z) < 1e-12:
            out[:, j] = z
            continue
        k = kinds[j]
        if k == 'bin':
            lv = int(rng.choice([3, 4, 5, 6, 8, 10, 12, 20]))
            v = qbin(z, lv)
            if rng.random() < 0.5:  # ordinal codes vs ratings-like offset
                v = v + 1.0
            out[:, j] = v
        elif k == 'binary':
            thr = np.quantile(z, rng.uniform(0.5, 0.93))
            out[:, j] = (z > thr).astype(np.float64)
        elif k == 'count':
            sc = rng.uniform(0.6, 1.5)
            base = np.expm1(np.clip(z * sc + rng.uniform(0.0, 2.0), -10.0, 12.0))
            v = np.floor(np.maximum(base, 0.0))
            out[:, j] = v
        elif k == 'lognorm':
            sc = rng.uniform(0.9, 2.4)
            v = np.exp(np.clip(z * sc, -18.0, 18.0)) * rng.uniform(1.0, 1000.0)
            out[:, j] = v
        elif k == 'power':
            p = rng.uniform(3.0, 5.0)
            v = np.sign(z) * np.power(np.abs(z), p)
            out[:, j] = v * rng.uniform(0.5, 5.0)
        elif k == 'censor':
            lo = np.quantile(z, rng.uniform(0.0, 0.12))
            hi = np.quantile(z, rng.uniform(0.88, 1.0))
            v = np.clip(z, lo, hi)
            v = (v - lo) * rng.uniform(1.0, 30.0)
            if rng.random() < 0.5:
                v = np.round(v)  # bounded integers (ages, scores)
            out[:, j] = v
        else:
            out[:, j] = z * rng.uniform(0.5, 3.0) + rng.uniform(-5.0, 5.0)

    # --- redundancy: a few columns become near-duplicates of another column ---
    if d >= 2:
        n_dup = int(rng.binomial(d, 0.22))
        if n_dup > 0:
            tgt = rng.choice(d, size=min(n_dup, d - 1), replace=False)
            for j in tgt:
                src = int(rng.integers(d))
                if src == j:
                    src = (src + 1) % d
                s = out[:, src]
                sd = s.std()
                if not np.isfinite(sd) or sd <= 1e-9:
                    continue
                a = rng.uniform(0.5, 2.0) * (1.0 if rng.random() < 0.8 else -1.0)
                noise = rng.normal(0.0, sd * rng.uniform(0.0, 0.15), size=n)
                v = a * s + rng.uniform(-1.0, 1.0) * sd + noise
                if np.allclose(s, np.round(s)):
                    v = np.round(v)
                out[:, j] = v

    out = np.nan_to_num(out, nan=0.0, posinf=0.0, neginf=0.0)
    out = np.clip(out, -1e12, 1e12)
    # keep magnitudes representable in float32 while preserving shape/order
    mx = np.max(np.abs(out), axis=0)
    scale = np.where(mx > 1e9, 1e9 / np.maximum(mx, 1e-12), 1.0)
    out = out * scale
    return np.nan_to_num(out.astype(np.float32), nan=0.0, posinf=0.0, neginf=0.0)

